import EventEmitter from 'eventemitter3'

import { afterEach, describe, expect, it, jest } from '@jest/globals'

import { DENYLIST } from '../config'
import { ScreenAgent } from '../index'
import { AdviceGenerator } from '../advice-generator'
import { AgentMode, type AgentAction } from '../types'
import { SafetyGate } from '../safety-gate'

let lastMockSocket: MockSocket | null = null

type MockSocket = {
  url: string
  on: (ev: string, fn: (...args: unknown[]) => void) => void
  once: (ev: string, fn: (...args: unknown[]) => void) => void
  off: (ev: string, fn: (...args: unknown[]) => void) => void
  send: jest.Mock
  close: jest.Mock
  terminate: jest.Mock
  removeAllListeners: jest.Mock
  emitMessage: (payload: Record<string, unknown>) => void
}

function createMockSocket(url: string): MockSocket {
  const messageHandlers: Array<(data: unknown) => void> = []
  const socket: MockSocket = {
    url,
    on(ev: string, fn: (...args: unknown[]) => void) {
      if (ev === 'message') {
        messageHandlers.push(fn as (data: unknown) => void)
      }
    },
    once(ev: string, fn: (...args: unknown[]) => void) {
      if (ev === 'open') {
        queueMicrotask(() => {
          fn()
        })
      }
    },
    off: jest.fn(),
    send: jest.fn(),
    close: jest.fn(),
    terminate: jest.fn(),
    removeAllListeners: jest.fn(),
    emitMessage(payload: Record<string, unknown>) {
      const raw = JSON.stringify(payload)
      for (const h of messageHandlers) {
        h(raw)
      }
    },
  }
  return socket
}

jest.mock('ws', () => ({
  __esModule: true,
  default: jest.fn((url: string) => {
    lastMockSocket = createMockSocket(url)
    return lastMockSocket
  }),
}))

async function flushPromises(): Promise<void> {
  await new Promise<void>((r) => setImmediate(r))
  await new Promise<void>((r) => setImmediate(r))
}

function totalListeners(ee: EventEmitter): number {
  let n = 0
  for (const ev of ee.eventNames()) {
    n += ee.listenerCount(ev as string)
  }
  return n
}

describe('Screen agent — runtime regression (voice coexistence)', () => {
  afterEach(() => {
    lastMockSocket = null
  })

  it('ScreenAgent initializes without touching voice agent state', async () => {
    const voiceAgentEmitter = new EventEmitter()
    expect(totalListeners(voiceAgentEmitter)).toBe(0)

    const agent = new ScreenAgent({ wsPort: 8765 })
    await agent.initialize()

    expect(totalListeners(voiceAgentEmitter)).toBe(0)

    const internal = (agent as unknown as { emitter: EventEmitter }).emitter
    expect(internal.eventNames().length).toBeGreaterThan(0)
    expect(totalListeners(internal)).toBeGreaterThan(0)

    agent.stop()
  })

  it("jarvis:speak event from screen agent has correct shape", async () => {
    lastMockSocket = null
    const adviceGen = {
      generate: jest.fn(async () => 'Check the build output.'),
    } as unknown as AdviceGenerator
    const agent = new ScreenAgent({ wsPort: 8765 }, { adviceGenerator: adviceGen })
    let payload: { text: string; priority: 'low' | 'normal' | 'high' } | null = null
    agent.on('jarvis:speak', (p) => {
      payload = p
    })
    await agent.initialize()
    await agent.setMode(AgentMode.ADVISE)
    expect(lastMockSocket).not.toBeNull()
    lastMockSocket!.emitMessage({
      type: 'screen_change',
      frame_id: 1,
      app: 'Code',
      windowTitle: 'x',
      error_detected: true,
      timestamp: Date.now() / 1000,
      element_count: 0,
    })
    await flushPromises()
    expect(payload).not.toBeNull()
    expect(typeof payload!.text).toBe('string')
    expect(payload!.text.length).toBeGreaterThan(0)
    expect(['low', 'normal', 'high']).toContain(payload!.priority)
    agent.stop()
  })

  it('screen agent stop() does not affect other agents', async () => {
    lastMockSocket = null
    const otherAgent = new EventEmitter()
    const spy = jest.spyOn(otherAgent, 'emit')

    const agent = new ScreenAgent({ wsPort: 8765 })
    await agent.initialize()
    agent.stop()

    expect(spy).not.toHaveBeenCalled()
    spy.mockRestore()
  })

  it('screen agent mode switch does not emit unexpected events', async () => {
    lastMockSocket = null
    const agent = new ScreenAgent({ wsPort: 8765 })
    await agent.initialize()
    const internal = (agent as unknown as { emitter: EventEmitter }).emitter
    const emitted: string[] = []
    const orig = internal.emit.bind(internal)
    internal.emit = ((event: string, ...args: unknown[]) => {
      emitted.push(event)
      return orig(event, ...args)
    }) as typeof internal.emit

    await agent.setMode(AgentMode.ADVISE)

    expect(emitted.every((name) => name === 'screen:change')).toBe(true)

    agent.stop()
  })

  it('DENYLIST blocks all critical destructive actions', () => {
    const gate = new SafetyGate()
    const entries = [...DENYLIST]
    let n = 0
    for (const phrase of entries) {
      const action: AgentAction = {
        type: 'test',
        reasoning: `User asked to run: ${phrase} on the server`,
        needsApproval: false,
      }
      expect(gate.isBlocked(action)).toBe(true)
      n += 1
    }
    // eslint-disable-next-line no-console
    console.info(`[regression] DENYLIST entries tested: ${String(n)}`)
    expect(n).toBe(entries.length)
  })
})

import { existsSync, readFileSync, readdirSync } from 'node:fs'
import { join, relative } from 'node:path'

import { describe, expect, it } from '@jest/globals'
import { globSync } from 'glob'

const SCREEN_AGENT_ROOT = join(__dirname, '..')
const REPO_ROOT = join(__dirname, '..', '..', '..', '..')

function productionTsFiles(): string[] {
  const rel = globSync('**/*.ts', {
    cwd: SCREEN_AGENT_ROOT,
    ignore: ['**/__tests__/**'],
    nodir: true,
    posix: true,
  })
  return rel.map((r) => join(SCREEN_AGENT_ROOT, r))
}

function readProductionSources(): Array<{ path: string; text: string; lines: string[] }> {
  const out: Array<{ path: string; text: string; lines: string[] }> = []
  for (const file of productionTsFiles()) {
    const text = readFileSync(file, 'utf8')
    out.push({ path: file, text, lines: text.split(/\r?\n/) })
  }
  return out
}

const FORBIDDEN_IMPORT_TOKENS: readonly string[] = [
  'elevenlabs',
  "from '../voice",
  "from '../../services/tts",
  "from '../../services/stt",
  "from '../../services/elevenlabs",
  "require('elevenlabs",
  "require('../voice",
]

const DIRECT_VOICE_CALL_PATTERNS: readonly string[] = [
  '.speak(',
  '.synthesize(',
  '.playAudio(',
  'ttsService.',
  'voiceService.',
  'elevenlabsClient.',
]

/** Lines may use `this.emit('jarvis:speak'` or `this.emit("jarvis:speak"`. */
function lineUsesAllowedJarvisSpeakEmit(line: string): boolean {
  return /\bthis\.emit\s*\(\s*['"]jarvis:speak['"]/.test(line)
}

function findMatchesWithLines(
  lines: string[],
  predicate: (line: string, lineNumber: number) => boolean,
): Array<{ line: number; text: string }> {
  const hits: Array<{ line: number; text: string }> = []
  lines.forEach((text, i) => {
    if (predicate(text, i + 1)) {
      hits.push({ line: i + 1, text })
    }
  })
  return hits
}

describe('Voice boundary — static analysis (screen agent)', () => {
  it('screen agent imports no voice/TTS/ElevenLabs services', () => {
    const violations: string[] = []
    for (const file of productionTsFiles()) {
      const text = readFileSync(file, 'utf8')
      const lower = text.toLowerCase()
      for (const token of FORBIDDEN_IMPORT_TOKENS) {
        const hit = token === 'elevenlabs' ? lower.includes('elevenlabs') : text.includes(token)
        if (hit) {
          violations.push(`${relative(REPO_ROOT, file)} — forbidden substring: ${JSON.stringify(token)}`)
        }
      }
    }
    if (violations.length > 0) {
      // eslint-disable-next-line no-console
      console.error(violations.join('\n'))
    }
    expect(violations).toEqual([])
  })

  it('screen agent speaks only via jarvis:speak event — never direct call', () => {
    const violations: Array<{ file: string; line: number; pattern: string; text: string }> = []
    for (const { path: file, lines } of readProductionSources()) {
      for (const pattern of DIRECT_VOICE_CALL_PATTERNS) {
        const hits = findMatchesWithLines(lines, (line) => {
          if (!line.includes(pattern)) {
            return false
          }
          if (lineUsesAllowedJarvisSpeakEmit(line)) {
            return false
          }
          return true
        })
        for (const h of hits) {
          violations.push({
            file: relative(REPO_ROOT, file),
            line: h.line,
            pattern,
            text: h.text.trim(),
          })
        }
      }
    }
    if (violations.length > 0) {
      for (const v of violations) {
        // eslint-disable-next-line no-console
        console.error(`${v.file}:${v.line} — matched ${JSON.stringify(v.pattern)} — ${v.text}`)
      }
    }
    expect(violations).toEqual([])
  })

  // eslint-disable-next-line sonarjs/cognitive-complexity -- test validates source-level voice boundary across all production files; multi-pass inspection is inherent
  it('jarvis:speak is the only voice output mechanism in screen agent', () => {
    let jarvisSpeakThisEmitCount = 0
    let jarvisSpeakEmitterEmitCount = 0

    const extraVoiceEmitViolations: string[] = []

    for (const { path: file, lines } of readProductionSources()) {
      for (const line of lines) {
        if (/\bthis\.emit\s*\(\s*['"]jarvis:speak['"]/.test(line)) {
          jarvisSpeakThisEmitCount += 1
        }
        if (/\bthis\.emitter\.emit\s*\(\s*['"]jarvis:speak['"]/.test(line)) {
          jarvisSpeakEmitterEmitCount += 1
        }
      }
      for (let i = 0; i < lines.length; i += 1) {
        const line = lines[i]!
        if (/^\s*\/\//.test(line) || /\/\*/.test(line)) {
          continue
        }
        if (lineUsesAllowedJarvisSpeakEmit(line)) {
          continue
        }
        if (/\bthis\.emitter\.emit\s*\(\s*['"]jarvis:speak['"]/.test(line)) {
          continue
        }
        const suspicious =
          /\.emit\s*\(\s*['"](tts|voice|audio|speech)/i.test(line) ||
          /\bnew\s+Audio\s*\(/i.test(line) ||
          /\bspeechSynthesis\b/i.test(line)
        if (suspicious) {
          extraVoiceEmitViolations.push(
            `${relative(REPO_ROOT, file)}:${i + 1} — unexpected voice/audio emission pattern: ${line.trim()}`,
          )
        }
      }
    }

    // eslint-disable-next-line no-console
    console.info(
      `[voice-boundary] this.emit('jarvis:speak'…) count: ${String(jarvisSpeakThisEmitCount)}; this.emitter.emit('jarvis:speak'…) count: ${String(jarvisSpeakEmitterEmitCount)}`,
    )

    expect(jarvisSpeakThisEmitCount + jarvisSpeakEmitterEmitCount).toBeGreaterThanOrEqual(1)
    expect(extraVoiceEmitViolations).toEqual([])
  })

  it('voice agent files exist and have not been deleted', () => {
    const voiceDir = join(REPO_ROOT, 'src', 'agents', 'voice')
    expect(existsSync(voiceDir)).toBe(true)
    const tsFiles: string[] = []
    const walk = (dir: string): void => {
      for (const ent of readdirSync(dir, { withFileTypes: true })) {
        const p = join(dir, ent.name)
        if (ent.isDirectory()) {
          walk(p)
        } else if (ent.name.endsWith('.ts')) {
          tsFiles.push(relative(REPO_ROOT, p))
        }
      }
    }
    walk(voiceDir)
    // eslint-disable-next-line no-console
    console.info(`[voice-boundary] src/agents/voice/ .ts files: ${tsFiles.join(', ') || '(none)'}`)
    expect(tsFiles.length).toBeGreaterThanOrEqual(1)
  })

  it('screen agent folder structure is complete', () => {
    const expected = [
      'src/agents/screen-agent/types.ts',
      'src/agents/screen-agent/config.ts',
      'src/agents/screen-agent/python-bridge.ts',
      'src/agents/screen-agent/state-manager.ts',
      'src/agents/screen-agent/significance-detector.ts',
      'src/agents/screen-agent/advice-generator.ts',
      'src/agents/screen-agent/safety-gate.ts',
      'src/agents/screen-agent/goal-executor.ts',
      'src/agents/screen-agent/index.ts',
    ]
    const missing: string[] = []
    for (const rel of expected) {
      const abs = join(REPO_ROOT, rel)
      if (!existsSync(abs)) {
        missing.push(rel)
      }
    }
    if (missing.length > 0) {
      // eslint-disable-next-line no-console
      console.error(`Missing screen-agent files:\n${missing.join('\n')}`)
    }
    expect(missing).toEqual([])
  })
})

import { JarvisBrowser } from '@/browser/jarvis-browser-runtime'
import { sanitizeRedirectUrl } from '@/lib/url-validation'
import { showBrowserToast } from '@/ui/toast/toast-helpers'

export const BROWSER_ACT_GOAL_CONTINUE = 'continue where you left off in your browser'

export const BROWSER_ACT_GOAL_OPEN_URL = 'open url in browser'

export type BrowserActContinueResult =
  | { mode: 'restored'; tabCount: number }
  | { mode: 'new_tab' }

export type JarvisBrowserActIpcPayload = {
  goal: string
  slots: Record<string, string | undefined>
}

/** True when this ACT goal should run in the renderer (Jarvis browser API + session store live there). */
export function shouldDelegateJarvisBrowserActGoal(goal: string): boolean {
  // eslint-disable-next-line no-regex-spaces
  const n = goal.trim().toLowerCase().replace(/\s+/g, ' ')
  if (n === BROWSER_ACT_GOAL_CONTINUE) return true
  if (n === 'continue where i left off in the browser.') return true
  if (n === 'continue where i left off in the browser') return true
  return n.includes('continue where') && n.includes('left off') && n.includes('browser')
}

export function shouldDelegateOpenUrlBrowserActGoal(goal: string): boolean {
  const n = goal.trim().toLowerCase()
  return n === BROWSER_ACT_GOAL_OPEN_URL || n.startsWith(`${BROWSER_ACT_GOAL_OPEN_URL} `)
}

export function shouldDelegateJarvisBrowserActToRenderer(goal: string): boolean {
  return shouldDelegateJarvisBrowserActGoal(goal) || shouldDelegateOpenUrlBrowserActGoal(goal)
}

export const ScreenBrowserAct = {
  async focusBrowserModal(openBrowserModal: () => void): Promise<void> {
    openBrowserModal()
  },

  async continueWhereLeftOff(openBrowserModal: () => void): Promise<BrowserActContinueResult> {
    openBrowserModal()
    await new Promise<void>((resolve) => {
      setTimeout(resolve, 120)
    })

    const session = await JarvisBrowser.getCurrentSession()
    if (session.tabs.length > 0) {
      return { mode: 'restored', tabCount: session.tabs.length }
    }

    try {
      await JarvisBrowser.openNewTab()
    } catch {
      /* shell may still show default new tab */
    }

    return { mode: 'new_tab' }
  },

  async openUrl(url: string, openBrowserModal: () => void): Promise<void> {
    // Validate URL before navigation — reject cross-origin or dangerous schemes
    const safeUrl = sanitizeRedirectUrl(url, [])
    if (!safeUrl) {
      const LOG_PREFIX = '[BrowserAct]'
      console.warn(`${LOG_PREFIX} Rejected unsafe URL for navigation: ${String(url).slice(0, 100)}`)
      throw new Error(`Invalid or unsafe URL: ${String(url).slice(0, 50)}…`)
    }

    openBrowserModal()
    await new Promise<void>((resolve) => {
      setTimeout(resolve, 120)
    })
    await JarvisBrowser.openUrl(safeUrl, { inNewTab: true })
  },
}

/**
 * Handles in-app browser ACT goals in the renderer (after main delegates via IPC).
 */
export async function handleBrowserActGoal(
  goal: string,
  slots: Record<string, string | undefined>,
  openBrowserModal: () => void
): Promise<void> {
  const normalised = goal.trim().toLowerCase()

  if (shouldDelegateJarvisBrowserActGoal(goal)) {
    const result = await ScreenBrowserAct.continueWhereLeftOff(openBrowserModal)
    if (result.mode === 'restored') {
      const tabWord = result.tabCount === 1 ? '' : 's'
      showBrowserToast(
        `Restored your last browser session (${String(result.tabCount)} tab${tabWord}).`,
        'success'
      )
    } else {
      showBrowserToast(
        'No previous browser session to restore; opened a new tab instead.',
        'warning'
      )
    }
    return
  }

  if (shouldDelegateOpenUrlBrowserActGoal(goal)) {
    const fromSlot = typeof slots.url === 'string' ? slots.url.trim() : ''
    const stripped = normalised.replace(BROWSER_ACT_GOAL_OPEN_URL, '').trim()
    const url = fromSlot || stripped
    if (url) {
      await ScreenBrowserAct.openUrl(url, openBrowserModal)
      showBrowserToast(`Opened ${url} in browser.`, 'success')
    } else {
      showBrowserToast('Open URL in browser: no URL provided.', 'warning')
    }
  }
}

import { useEffect, useRef, useState } from 'react'
import { MarkdownRenderer } from '@/components/MarkdownRenderer'
import { generateId } from '@/lib/helpers'
import type { IdeAttachment, IdeChatMode } from '@/lib/jarvis-ide-chat-types'

export type { IdeAttachment, IdeChatMode }

export interface IdeChatMessage {
  readonly id: string
  readonly role: 'user' | 'assistant'
  readonly content: string
  readonly reasoning?: string
  readonly attachments?: IdeAttachment[]
}

interface OpenFile {
  id: string
  filename: string
  language: string
}

interface IdeChatPanelProps {
  readonly messages: IdeChatMessage[]
  readonly loading: boolean
  readonly disabled: boolean
  readonly onSend: (text: string, attachments?: IdeAttachment[]) => void
  readonly onClear: () => void
  readonly themeColors: { readonly tc: string; readonly sb: string; readonly bc: string }
  /** Open editor tabs for @-context picker. */
  readonly openFiles?: OpenFile[]
  /** Callback to read file content for @ attachment. */
  readonly onGetFileContent?: (fileId: string) => string | null
  readonly onReview?: () => void
  readonly reviewDisabled?: boolean
  readonly qualityLoading?: boolean
  readonly onUndoAll?: () => void
  readonly onKeepAll?: () => void
  readonly undoKeepDisabled?: boolean
  /** Current panel mode. */
  readonly mode?: IdeChatMode
  readonly onModeChange?: (mode: IdeChatMode) => void
  /** Agent/autopilot status. */
  readonly agentStatus?: 'idle' | 'running' | 'paused'
  readonly onStopAgent?: () => void
  /** Model selector. */
  readonly model?: string
  readonly onModelChange?: (model: string) => void
  readonly modelOptions?: Array<{ id: string; label: string }>
}

const MODE_TIPS: Record<IdeChatMode, string> = {
  chat: 'Ask questions, get explanations, code help',
  composer: 'Plan structured changes step-by-step before applying',
  agent: 'Jarvis works autonomously — plan, code, run, fix, iterate',
}

const MODE_PLACEHOLDERS: Record<IdeChatMode, string> = {
  chat: 'Ask about your code, request changes, explain errors…',
  composer: 'Describe what you want to build or change — Jarvis will plan it…',
  agent: 'Give Jarvis a goal and he will work autonomously…',
}

// eslint-disable-next-line sonarjs/cognitive-complexity -- React component with multiple conditional interaction paths; decomposition into sub-components is tracked separately
export function IdeChatPanel({
  messages,
  loading,
  disabled,
  onSend,
  onClear,
  themeColors,
  openFiles = [],
  onGetFileContent,
  onReview,
  reviewDisabled = false,
  qualityLoading = false,
  onUndoAll,
  onKeepAll,
  undoKeepDisabled = true,
  mode = 'chat',
  onModeChange,
  agentStatus = 'idle',
  onStopAgent,
  model,
  onModelChange,
  modelOptions = [],
}: IdeChatPanelProps) {
  const { tc, sb, bc } = themeColors
  const [draft, setDraft] = useState('')
  const [attachments, setAttachments] = useState<IdeAttachment[]>([])
  const [showAtPicker, setShowAtPicker] = useState(false)
  const [atFilter, setAtFilter] = useState('')
  const endRef = useRef<HTMLDivElement>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)
  const imgInputRef = useRef<HTMLInputElement>(null)
  const atPickerRef = useRef<HTMLDivElement>(null)
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages, loading])

  // Close @ picker on outside click
  useEffect(() => {
    if (!showAtPicker) return
    const handler = (e: MouseEvent) => {
      if (atPickerRef.current && !atPickerRef.current.contains(e.target as Node)) {
        setShowAtPicker(false)
        setAtFilter('')
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [showAtPicker])

  const submit = () => {
    const t = draft.trim()
    if (!t || loading || disabled) return
    onSend(t, attachments.length > 0 ? attachments : undefined)
    setDraft('')
    setAttachments([])
  }

  const removeAttachment = (name: string) => {
    setAttachments((prev) => prev.filter((a) => a.name !== name))
  }

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>, asImage = false) => {
    const files = e.target.files
    if (!files?.length) return
    for (const file of Array.from(files)) {
      if (asImage || file.type.startsWith('image/')) {
        const reader = new FileReader()
        // eslint-disable-next-line sonarjs/no-nested-functions -- FileReader.onload must be set inline; closure captures file metadata
        reader.onload = () => {
          setAttachments((prev) => [
            ...prev.filter((a) => a.name !== file.name),
            { name: file.name, content: reader.result as string, mimeType: file.type || 'image/png', isImage: true },
          ])
        }
        reader.readAsDataURL(file)
      } else {
        const reader = new FileReader()
        // eslint-disable-next-line sonarjs/no-nested-functions -- FileReader.onload must be set inline; closure captures file metadata
        reader.onload = () => {
          setAttachments((prev) => [
            ...prev.filter((a) => a.name !== file.name),
            { name: file.name, content: reader.result as string, mimeType: file.type || 'text/plain', isImage: false },
          ])
        }
        reader.readAsText(file)
      }
    }
    e.target.value = ''
  }

  const handleAddFileContext = (file: OpenFile) => {
    const content = onGetFileContent?.(file.id) ?? ''
    const name = `@${file.filename}`
    setAttachments((prev) => [
      ...prev.filter((a) => a.name !== name),
      { name, content, mimeType: 'text/plain', isImage: false },
    ])
    setShowAtPicker(false)
    setAtFilter('')
    textareaRef.current?.focus()
  }

  const filteredFiles = openFiles.filter((f) =>
    atFilter ? f.filename.toLowerCase().includes(atFilter.toLowerCase()) : true
  )

  const isAgentRunning = mode === 'agent' && agentStatus === 'running'
  let loadingLabel = 'Thinking…'
  if (isAgentRunning) loadingLabel = '🤖 Agent is working…'
  else if (mode === 'composer') loadingLabel = '📝 Planning…'

  return (
    <div className="flex h-full min-h-0 flex-col" style={{ background: sb }}>

      {/* ── MODE SELECTOR ── */}
      <div className="flex-shrink-0 border-b" style={{ borderColor: bc }}>
        {/* Mode tabs */}
        <div className="flex items-center gap-0 px-1 pt-1">
          {(['chat', 'composer', 'agent'] as IdeChatMode[]).map((m) => (
            <button
              key={m}
              type="button"
              title={MODE_TIPS[m]}
              onClick={() => onModeChange?.(m)}
              className="relative px-3 py-1.5 text-[11px] font-medium rounded-t transition-colors capitalize"
              style={{
                color: mode === m ? tc : `${tc}55`,
                background: mode === m ? `${tc}0e` : 'transparent',
                borderBottom: `2px solid ${mode === m ? '#007acc' : 'transparent'}`,
              }}
            >
              {{ chat: 'Chat', composer: 'Composer', agent: 'Agent' }[m]}
              {m === 'agent' && agentStatus === 'running' && (
                <span className="ml-1 inline-block w-1.5 h-1.5 rounded-full bg-green-400 animate-pulse align-middle" />
              )}
            </button>
          ))}
          <div className="flex-1" />
          <button
            type="button"
            className="px-1.5 py-1 text-[10px] rounded hover:bg-white/10 mr-1"
            style={{ color: `${tc}40` }}
            onClick={onClear}
            disabled={messages.length === 0 || loading}
            title="Clear conversation"
          >
            Clear
          </button>
        </div>

        {/* Model + status row */}
        <div className="flex items-center gap-1.5 px-2 pb-1.5 pt-0.5">
          {modelOptions.length > 0 && onModelChange ? (
            <select
              value={model}
              onChange={(e) => onModelChange(e.target.value)}
              className="flex-1 h-6 px-1.5 text-[10px] rounded border-0 outline-none min-w-0"
              style={{ background: `${tc}10`, color: `${tc}85` }}
              title="IDE chat model"
            >
              {modelOptions.map((o) => (
                <option key={o.id} value={o.id}>{o.label}</option>
              ))}
            </select>
          ) : (model && (
            <span className="text-[10px] truncate" style={{ color: `${tc}40` }}>{model}</span>
          ))}

          {isAgentRunning && onStopAgent ? (
            <button
              type="button"
              onClick={onStopAgent}
              className="px-1.5 py-0.5 text-[10px] font-bold rounded"
              style={{ color: '#ef4444', border: '1px solid #ef444440' }}
              title="Stop agent"
            >
              ■ Stop
            </button>
          ) : (
            <div className="flex items-center gap-1 ml-auto">
              {onUndoAll && (
                <button
                  type="button"
                  className="text-[10px] hover:underline disabled:opacity-25"
                  style={{ color: `${tc}40` }}
                  disabled={undoKeepDisabled}
                  title="Undo all pending AI edits"
                  onClick={onUndoAll}
                >
                  Undo
                </button>
              )}
              {onKeepAll && (
                <button
                  type="button"
                  className="text-[10px] hover:underline disabled:opacity-25"
                  style={{ color: `${tc}40` }}
                  disabled={undoKeepDisabled}
                  title="Keep all pending AI edits"
                  onClick={onKeepAll}
                >
                  Keep
                </button>
              )}
            </div>
          )}
        </div>
      </div>

      {/* ── MESSAGES ── */}
      <div className="min-h-0 flex-1 space-y-3 overflow-y-auto px-2 py-2 text-[12px]">
        {messages.length === 0 && !loading && (
          <p className="px-1 leading-relaxed text-[11px]" style={{ color: `${tc}38` }}>
            {MODE_TIPS[mode]}
          </p>
        )}
        {messages.map((m) => (
          <div
            key={m.id}
            className={`rounded-md px-2.5 py-2 ${m.role === 'user' ? 'ml-3' : 'mr-1'}`}
            style={{
              background: m.role === 'user' ? `${tc}16` : `${tc}07`,
              border: `1px solid ${m.role === 'user' ? tc + '10' : tc + '05'}`,
            }}
          >
            {m.role === 'user' ? (
              <div>
                <p className="whitespace-pre-wrap text-[12px]" style={{ color: tc }}>{m.content}</p>
                {m.attachments && m.attachments.length > 0 && (
                  <div className="mt-1.5 flex flex-wrap gap-1">
                    {m.attachments.map((a) => (
                      <span
                        key={a.name}
                        className="inline-flex items-center gap-1 rounded px-1.5 py-0.5 text-[10px]"
                        style={{ background: `${tc}12`, color: `${tc}65` }}
                      >
                        {a.isImage ? '🖼' : '📄'} {a.name}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            ) : (
              <>
                {m.reasoning && (
                  <details className="mb-2 rounded border px-2 py-1 text-[11px]" style={{ borderColor: `${tc}20`, color: `${tc}70` }}>
                    <summary className="cursor-pointer select-none">Thinking</summary>
                    <pre className="mt-1 max-h-28 overflow-auto whitespace-pre-wrap font-mono text-[10px]" style={{ color: `${tc}90` }}>
                      {m.reasoning}
                    </pre>
                  </details>
                )}
                <div className="prose prose-invert max-w-none text-[12px] leading-relaxed [&_pre]:text-[11px]" style={{ color: `${tc}e0` }}>
                  <MarkdownRenderer content={m.content} onCitationHover={() => {}} />
                </div>
              </>
            )}
          </div>
        ))}
        {loading && (
          <div className="px-2 py-1 text-[11px] animate-pulse" style={{ color: isAgentRunning ? '#22c55e' : `${tc}50` }}>
            {loadingLabel}
          </div>
        )}
        <div ref={endRef} />
      </div>

      {/* ── COMPOSE BOX ── */}
      <div className="flex-shrink-0 border-t" style={{ borderColor: bc }}>

        {/* Attached files chips */}
        {attachments.length > 0 && (
          <div className="flex flex-wrap gap-1 px-2 pt-1.5 pb-0.5">
            {attachments.map((a) => (
              <span
                key={a.name}
                className="inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] max-w-[140px]"
                style={{ background: `${tc}12`, color: `${tc}75`, border: `1px solid ${tc}14` }}
              >
                {a.isImage ? '🖼' : '📄'}
                <span className="truncate">{a.name}</span>
                <button
                  type="button"
                  className="ml-0.5 opacity-60 hover:opacity-100 text-[11px] leading-none"
                  onClick={() => removeAttachment(a.name)}
                  title="Remove attachment"
                >
                  ×
                </button>
              </span>
            ))}
          </div>
        )}

        {/* @ file picker popover */}
        {showAtPicker && (
          <div
            ref={atPickerRef}
            className="mx-2 mb-1 rounded border shadow-lg overflow-hidden"
            style={{ background: sb, borderColor: `${tc}20` }}
          >
            <div className="px-2 py-1 border-b" style={{ borderColor: `${tc}12` }}>
              <input
                autoFocus
                value={atFilter}
                onChange={(e) => setAtFilter(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Escape') { setShowAtPicker(false); setAtFilter('') }
                  if (e.key === 'Enter' && filteredFiles.length > 0) handleAddFileContext(filteredFiles[0])
                }}
                placeholder="Filter open files…"
                className="w-full bg-transparent text-[11px] outline-none"
                style={{ color: tc }}
              />
            </div>
            <div className="overflow-y-auto" style={{ maxHeight: 140 }}>
              {filteredFiles.length === 0 && (
                <p className="px-2 py-2 text-[10px]" style={{ color: `${tc}40` }}>No open files</p>
              )}
              {filteredFiles.map((f) => (
                <button
                  key={f.id}
                  type="button"
                  className="w-full px-2 py-1 text-left text-[11px] hover:bg-white/10 truncate flex items-center gap-1.5"
                  style={{ color: `${tc}c0` }}
                  onClick={() => handleAddFileContext(f)}
                >
                  <span className="opacity-50 text-[10px]">{f.language}</span>
                  {f.filename}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Textarea */}
        <div className="px-2 pt-1.5">
          <textarea
            ref={textareaRef}
            value={draft}
            onChange={(e) => setDraft(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault()
                submit()
              }
            }}
            placeholder={disabled ? 'Chat unavailable' : MODE_PLACEHOLDERS[mode]}
            disabled={disabled || loading}
            rows={3}
            className="w-full resize-none rounded border px-2 py-1.5 text-[12px] outline-none focus:ring-1"
            style={{
              background: `${tc}0a`,
              borderColor: `${tc}12`,
              color: tc,
              caretColor: tc,
            }}
          />
        </div>

        {/* Toolbar */}
        <div className="flex items-center gap-1 px-2 pb-2 pt-1">
          {/* Attach file */}
          <button
            type="button"
            title="Attach text file (📎)"
            className="w-6 h-6 flex items-center justify-center rounded text-[13px] hover:bg-white/10 transition-colors"
            style={{ color: `${tc}55` }}
            onClick={() => fileInputRef.current?.click()}
          >
            📎
          </button>

          {/* Attach image */}
          <button
            type="button"
            title="Attach image (🖼)"
            className="w-6 h-6 flex items-center justify-center rounded text-[13px] hover:bg-white/10 transition-colors"
            style={{ color: `${tc}55` }}
            onClick={() => imgInputRef.current?.click()}
          >
            🖼
          </button>

          {/* @-context picker */}
          <button
            type="button"
            title="Add open file as context"
            className="flex items-center gap-0.5 px-1.5 h-6 rounded text-[10px] font-mono hover:bg-white/10 transition-colors"
            style={{
              color: showAtPicker || attachments.some((a) => a.name.startsWith('@')) ? '#007acc' : `${tc}55`,
            }}
            onClick={() => setShowAtPicker((p) => !p)}
          >
            @{openFiles.length > 0 && (
              <span className="ml-0.5 opacity-50">{openFiles.length}</span>
            )}
          </button>

          <div className="flex-1" />

          {/* Review */}
          {onReview && (
            <button
              type="button"
              className="h-6 px-2 rounded text-[10px] font-medium transition-colors hover:bg-white/10 disabled:opacity-25"
              style={{ color: `${tc}65`, border: `1px solid ${tc}18` }}
              disabled={reviewDisabled || loading || qualityLoading}
              title="Run ESLint + tsc, then ask Jarvis to review"
              onClick={onReview}
            >
              {qualityLoading ? '…' : 'Review'}
            </button>
          )}

          {/* Send */}
          <button
            type="button"
            onClick={submit}
            disabled={!draft.trim() || loading || disabled}
            className="h-6 px-3 rounded text-[11px] font-semibold transition-opacity"
            style={{
              background: mode === 'agent' ? '#16a34a' : '#007acc',
              color: '#fff',
              opacity: draft.trim() && !loading && !disabled ? 1 : 0.35,
            }}
          >
            {mode === 'agent' && agentStatus === 'idle' ? '▶' : '→'}
          </button>
        </div>

        {/* Hidden file inputs */}
        <input
          ref={fileInputRef}
          type="file"
          multiple
          accept="*/*"
          className="hidden"
          onChange={(e) => handleFileUpload(e, false)}
        />
        <input
          ref={imgInputRef}
          type="file"
          multiple
          accept="image/*"
          className="hidden"
          onChange={(e) => handleFileUpload(e, true)}
        />
      </div>
    </div>
  )
}

